#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e6+6;
bool vis[MAXN];
int n,g,ans,k[MAXN];
vector<int> a[MAXN];
signed main(void)
{
    cl(vis);
    n=read(),g=read();
    ans=1;
	vis[1]=true;
    FOR(i,1,g)
	{
        k[i]=read();
        a[i].pb(0);
        FOR(j,1,k[i])
		{
            a[i].pb(0);
            a[i][j]=read();
        }
    }
    bool flag=true;
    while(flag)
	{
        bool tmp=false;
        FOR(i,1,g)
		{
            int num=0;
            FOR(j,1,k[i])
			{
                if(vis[a[i][j]])
				{
                    ++num;
                }
            }
            if(num==k[i]-1)
			{
                tmp=true;
                FOR(j,1,k[i])
				{
                    vis[a[i][j]]=true;
                }
                ++ans;
                break;
            }
        }
        flag=tmp;
    }
    write(ans);
    return false;
}
